export interface OCELTypeStats {
  event_type_counts: Record<string, number>;
  object_type_counts: Record<string, number>;
}

export interface OcpnArc {
  place: string;
  objectType: string;
  weight: number;
  variable: boolean;
  tokens: string[];
}

/** Return the firing (consume + produce token ids per place), or false when the
 *  transition cannot fire. */
export type OcpnFireGuard = (args: OcpnFireGuardArgs) => OcpnFiring | false;

export interface OcpnFireGuardArgs {
  transitionId: string;
  marking: TokenMarking;
  inputs: OcpnArc[];
  outputs: Omit<OcpnArc, "tokens">[];
}

export interface OcpnFiring {
  consume: Record<string, string[]>;
  produce: Record<string, string[]>;
}

/** One object instance involved in a firing, e.g. a token id paired with its object type. */
export interface OcSequenceObject {
  id: string;
  objectType: string;
}

/** One step of an object-centric simulation trace: a fired transition plus the object
 *  instances it touched. Objects are clustered and colored by type when rendered. */
export interface OcSequenceStep {
  transitionId: string;
  /** Activity label; null or empty for a silent (tau) transition. */
  label: string | null;
  /** Objects associated with this step (any number of types). */
  objects: OcSequenceObject[];
}

/** Petri net data shape. `label` is optional (serializes as missing/null); assignable to/from the generated `@r4pm/client` `PetriNet` type. */
export interface PetriNet {
  places: Array<{ id: string }>;
  transitions: Array<{ id: string; label?: string | null }>;
  arcs: Array<{
    nodes: [string, string];
    weight?: number;
  }>;
  initial_marking?: Record<string, number> | null;
  final_marking?: Record<string, number> | null;
}

export type PetriNetNode =
  | (Node<TransitionData> & { type: "transition" })
  | (Node<PlaceData> & { type: "place" });

/**
 * Presentation overlay for {@link PetriNetViewer}. Each resolver is optional and
 * called once per element; return a partial presentation (or nothing) to recolor,
 * relabel, restyle, or fully re-render that element. Identity:
 *  - transitions / places by `id`
 *  - arcs by `(from, to)` (a synthetic stable `id` is also passed)
 *
 * Decide styling from your own data (closure over a map keyed by id) and/or from
 * the `raw` element passed as the second arg (if your net carries extra fields).
 *
 * @example Color places + arcs by object type (the OCPN pattern):
 * ```tsx
 * const colorOf = (placeId: string) => typeColor[objectType[placeId]];
 * const overlay: PetriNetOverlay = {
 *   place: (p) => ({ style: { borderColor: colorOf(p.id) }, tokenColor: colorOf(p.id) }),
 *   arc:   (a) => ({ style: { stroke: colorOf(a.type === "PlaceTransition" ? a.from : a.to) } }),
 * };
 * <PetriNetViewer data={net} overlay={overlay} />
 * ```
 *
 * @example Render a custom marking (any JSX), not the default token dots:
 * ```tsx
 * const overlay: PetriNetOverlay = {
 *   place: (p) => ({ renderMarking: () => <MyTokens count={p.tokens} place={p.id} /> }),
 * };
 * ```
 *
 * See `object-centric-petri-net.tsx` for a full extension built on this.
 */
export interface PetriNetOverlay {
  transition?: (
    info: TransitionInfo,
    raw: PetriNet["transitions"][number],
  ) => ElementPresentation | undefined;
  place?: (info: PlaceInfo, raw: PetriNet["places"][number]) => PlacePresentation | undefined;
  arc?: (info: ArcInfo, raw: PetriNet["arcs"][number]) => ElementPresentation | undefined;
}

/**
 * Readonly Petri net where clicking an enabled transition fires it: consume input
 * tokens, produce output tokens. Tokens are indistinguishable counts.
 */
export interface PetriNetSimulatorProps extends ViewerProps<PetriNet> {
  /** When provided, a "Save as log" button appears; called with every recorded trace
   *  (the current one finalized) so a host can turn them into an event-log dataset with
   *  one case per trace. Kept out of the pure component. */
  onSaveAsLog?: (traces: SimTrace[]) => void;
  /** When true, clicking a not-enabled transition force-fires it (token-replay style): the
   *  missing input tokens are counted into the trace and firing proceeds anyway. Default false. */
  allowForcedFiring?: boolean;
}

/** Props of {@link PetriNetViewer}: the standard viewer props plus an optional
 *  presentation overlay used by alignment-style views. Backward compatible: the
 *  overlay defaults to undefined. */
export interface PetriNetViewerProps extends ViewerProps<PetriNet> {
  overlay?: PetriNetOverlay;
  /** Allow structural + marking editing. The editable viewer is uncontrolled:
   *  it lays out `data` on mount and reports edits via `onChange`; do not feed
   *  `onChange` output straight back as `data` (use a `key` to force a reset). */
  editable?: boolean;
  /** Called with the serialized net after each edit. */
  onChange?: (net: PetriNet) => void;
}

export interface PetriNetWorkbenchProps extends ViewerProps<PetriNet> {
  /** Mode shown on mount. Defaults to "view". */
  initialMode?: PetriNetMode;
  /** Fired whenever the current (possibly edited) net changes. */
  onNetChange?: (net: PetriNet) => void;
  /** Host-supplied buttons (e.g. backend PNML export); receive the current net. */
  toolbar?: (net: PetriNet) => ReactNode;
  /** Host handler to turn the recorded replay traces into an event-log dataset. When
   *  set, the replay view shows a "Save as log" button. */
  onSaveTraceAsLog?: (traces: SimTrace[]) => void;
  /** Initial state of the replay view's "Force fire" toggle (force-fire not-enabled
   *  transitions, token-replay style). Defaults to off; the user can flip it in the toolbar. */
  allowForcedFiring?: boolean;
}

export type PlaceData = ElementHandlers & {
  label?: string | undefined;
  tokens?: number;
  finalTokens?: number;
  /** Color of the default token dots (defaults to black). */
  tokenColor?: string;
  /** Explicit per-token marks; render-safe in both DOM and SVG export. Takes
   *  precedence over tokens/finalTokens; superseded by `renderMarking` on screen. */
  tokenMarks?: TokenMark[];
  className?: string;
  style?: React.CSSProperties;
  /** Replace the marking rendering entirely (e.g. per-object-type tokens). */
  renderMarking?: () => React.ReactNode;
  /** Extra editable control rendered inside the place (e.g. object-type select). */
  renderControls?: () => React.ReactNode;
  /** Consumer attribute: the object type this place belongs to (OCPN). Stored on the
   *  node so the editor is the single source of truth; serialized back out. */
  objectType?: string;
};

export interface PlaceInfo {
  id: string;
  /** Token count from the net's initial marking (before any override). */
  tokens: number;
  /** Token count from the net's final marking (before any override). */
  finalTokens: number;
}

/** What a place resolver returns; adds marking controls. */
export interface PlacePresentation extends ElementInteractions {
  style?: CSSProperties;
  className?: string;
  label?: string;
  /** Token count to draw (overrides the initial marking). */
  tokens?: number;
  /** Color of the default token dots. */
  tokenColor?: string;
  /** Explicit per-token marks (dots/squares, colored/faded); rendered in both the
   *  DOM node and the SVG export. Takes precedence over `tokens`. */
  tokenMarks?: TokenMark[];
  /** Render the marking yourself (e.g. per-object-type tokens). */
  renderMarking?: () => ReactNode;
  /** Extra editable control rendered inside the place (e.g. an object-type select). */
  renderControls?: () => ReactNode;
}

export interface RankedBarListProps {
  items: FreqItem[] | Record<string, number>;
  /** Scope passed to the shared colorOf resolver (e.g. "activity", "objectType"). */
  scope?: string;
  /** Override the color resolver; defaults to the shared ViewerConfig colorOf. */
  colorOf?: ColorResolver;
  /** Show at most this many rows (highest counts first). */
  max?: number;
  /** Format the value shown on the right (default: localized integer). */
  valueFormat?: (n: number) => string;
  onItemClick?: (key: string) => void;
  emptyText?: string;
}

export interface ResolvedMove {
  kind: MoveKind;
  /** Human-readable label: activity name for sync/log moves, transition label for model moves. */
  label: string;
  /** Transition has no label (invisible/tau). */
  hidden: boolean;
}

export interface SelectionActionsProps {
  /** Full set of selectable keys (for All / Invert). */
  allKeys: string[];
  value: Set<string>;
  onChange: (next: Set<string>) => void;
  size?: "1" | "2";
}

/** A replay trace plus token-replay bookkeeping (produced/consumed/missing/remaining). */
export interface SimTrace {
  steps: SimTraceStep[];
  /** Whether the marking was accepting (final marking reached) when the trace ended. */
  accepting: boolean;
  /** Tokens produced: initial marking plus every fired transition's output weights. */
  produced: number;
  /** Tokens consumed: every fired transition's input weights plus the final marking. */
  consumed: number;
  /** Tokens that had to be created to fire (input shortfall on a forced fire, plus any
   *  final-marking shortfall at trace end). */
  missing: number;
  /** Tokens left in the marking after consuming the final marking, at trace end. */
  remaining: number;
}

/** One fired step of a simulation trace. */
export interface SimTraceStep {
  transitionId: string;
  /** Transition label; null for a silent (tau) transition. */
  label: string | null;
}

export interface StatCardsProps {
  items: StatItem[];
  /** "start" = label over value, left aligned (metrics); "center" = centered big number. */
  align?: "start" | "center";
  /** Progress visualization for items with a `progress` value. Default "ring". */
  indicator?: StatIndicator;
}

export interface StatItem {
  label: string;
  value: string | number;
  hint?: string;
  /** Semantic direction; colors the value / indicator (e.g. high fitness = good). */
  tone?: StatTone;
  /** 0..1 fraction. When set, the value renders with the chosen progress indicator. */
  progress?: number;
}

export type SyncProdNetConstructionError =
  | { InvalidPlaceInMarking: PlaceID }
  | "NoFinalMarking"
  | "NoInitialMarking";

export interface TimeConfig {
  /** RFC3339 start applied to the first (non-manual) event of every case. */
  start: string;
  stepSeconds: number;
}

/** One drawn token: a dot or square, optionally colored/faded. Both the DOM node
 *  and the SVG export render from this, so overlay/simulator markings (e.g. a green
 *  "final reached" square) appear in exports too - unlike JSX `renderMarking`, which
 *  the standalone SVG builder cannot run. Omitted `color` falls back to the node text. */
export type TokenMark = { shape: "dot" | "square"; color?: string; opacity?: number; title?: string };

export interface TraceVariants {
  activities: string[];
  act_to_index: Record<string, number>;
  traces: [number[], number][];
}

export type TransitionData = ElementHandlers & {
  label?: string | undefined;
  className?: string;
  style?: React.CSSProperties;
  /** Replace the transition's inner content entirely (e.g. an icon). */
  renderContent?: () => React.ReactNode;
};

export interface TransitionFireStats {
  sync_fires: number;
  model_fires: number;
}

export interface TransitionInfo {
  id: string;
  label: string | null;
}

export interface VariantAlignmentResult {
  activities: string[];
  frequency: number;
  result: { Ok: AlignmentResult } | { Err: AlignmentError };
}

/**
 * One export control for every viewer.
 *
 * A viewer wrapped in `<ViewerExportFrame>` advertises a vector rendering of itself via
 * `useRegisterExport` (real `<svg>`, not a DOM snapshot); the frame turns that one source into the
 * SVG / PNG / JPEG menu entries (PNG/JPEG are the SVG rasterized client-side, honoring a scale
 * factor). A viewer that registers nothing still exports: the frame falls back to an html-to-image
 * snapshot of its content. Saving goes through the optional `onSave` (so a host can route it to a
 * native save dialog); the default is a browser download (no host wiring needed).
 */

/** A viewer's self-contained vector rendering of its current state. */
export interface VectorExportSource {
  /** Build the current view as a standalone SVG string, or null when not ready. */
  toSvg: () => string | null;
  /** Optional extra menu content (e.g. a per-viewer row-limit picker). */
  menuExtras?: ReactNode;
}

export interface ViewerAction {
  id: string;
  label: string;
  icon?: ComponentType<{ size?: number }>;
  /** Limit to a target scope (e.g. only "activity"); undefined = any element. */
  scope?: string;
  run: (target: ViewerTarget) => void;
}

/**
 * Cross-cutting viewer configuration + interactivity. A host sets it via `ViewerConfigProvider`;
 * `ViewerProps` may override any field; unset fields fall back to viewer defaults.
 */
export interface ViewerConfig {
  colorOf?: ColorResolver;
  format?: ViewerFormat;
  alignmentStyle?: AlignmentStyle;
  actions?: ViewerAction[];
  onSelect?: (target: ViewerTarget) => void;
  onElementContextMenu?: (target: ViewerTarget, event: { clientX: number; clientY: number }) => void;
}

export interface ViewerFormat {
  number?: (n: number) => string;
  date?: (ms: number) => string;
  duration?: (ms: number) => string;
}

export interface ViewerProps<T> extends ViewerConfig {
  data: T;
  /** Source object handle id, for drill-down. */
  handle?: string;
}

/** A domain element a host can act on. `scope` is the kind ("activity", "objectType", ...). */
export interface ViewerTarget {
  scope: string;
  key: string;
  data?: unknown;
}
